final:
module RefModule (
    input wire J,
    input wire K,
    input wire CLK,
    output reg Q
);
      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge CLK or posedge dbg_halt) begin
        if (J == 1'b0 && K == 1'b0) 
            Q <= Q; // No change
        else if (J == 1'b1 && K == 1'b0) 
            Q <= 1'b1; // Set
        else if (J == 1'b0 && K == 1'b1) 
            Q <= 1'b0; // Reset
        else if (J == 1'b1 && K == 1'b1) 
            Q <= ~Q; // Toggle
    end
endmodule
